"""
Cognitive Features API for Atlas
Provides endpoints for all cognitive amplification features.
"""

import os

from fastapi import APIRouter, HTTPException, Query
from pydantic import BaseModel
from typing import List, Optional, Dict, Any
from datetime import datetime

# Create router for cognitive features endpoints
cognitive_router = APIRouter(prefix="/cognitive", tags=["cognitive features"])

# Import Atlas cognitive features\nfrom ask.proactive.surfacer import ProactiveSurfacer\nfrom ask.temporal.temporal_engine import TemporalEngine\nfrom ask.socratic.question_engine import QuestionEngine\nfrom ask.recall.recall_engine import RecallEngine\nfrom ask.insights.pattern_detector import PatternDetector\nfrom helpers.metadata_manager import MetadataManager\n\n# Initialize core components\nmetadata_manager = MetadataManager()\nproactive_surfacer = ProactiveSurfacer(metadata_manager)\ntemporal_engine = TemporalEngine(metadata_manager)\nquestion_engine = QuestionEngine(metadata_manager)\nrecall_engine = RecallEngine(metadata_manager)\npattern_detector = PatternDetector(metadata_manager)\n\n# Data models\nclass ProactiveItem(BaseModel):\n    title: str\n    updated_at: str\n    relevance_score: Optional[float] = None\n\nclass TemporalRelationship(BaseModel):\n    from_title: str\n    to_title: str\n    days_apart: int\n    relationship_type: str\n    shared_tags: List[str]\n\nclass SocraticQuestion(BaseModel):\n    question: str\n    difficulty_level: Optional[int] = None\n\nclass RecallItem(BaseModel):\n    title: str\n    last_reviewed: Optional[str] = None\n    review_count: Optional[int] = None\n    difficulty_score: Optional[float] = None\n    review_urgency: Optional[float] = None\n\nclass TagPattern(BaseModel):\n    tag: str\n    frequency: int\n    trend: Optional[str] = None\n\nclass CognitiveInsight(BaseModel):\n    type: str\n    content: str\n    confidence: Optional[float] = None\n\n# Proactive Surfacer endpoints\n@cognitive_router.get(\"/proactive/items\", response_model=List[ProactiveItem])\nasync def get_forgotten_content(\n    limit: int = Query(10, ge=1, le=100),\n    cutoff_days: int = Query(30, ge=1, le=365)\n):\n    \"\"\"Get forgotten content that should be surfaced\"\"\"\n    try:\n        items = proactive_surfacer.surface_forgotten_content(n=limit, cutoff_days=cutoff_days)\n        result = []\n        for item in items:\n            result.append(ProactiveItem(\n                title=getattr(item, \"title\", \"Untitled\"),\n                updated_at=getattr(item, \"updated_at\", \"\"),\n                relevance_score=None  # Would be calculated in a full implementation\n            ))\n        return result\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting forgotten content: {str(e)}\")\n\n@cognitive_router.post(\"/proactive/items/{content_id}/mark-surfaced\")\nasync def mark_content_surfaced(content_id: str):\n    \"\"\"Mark a content item as surfaced\"\"\"\n    try:\n        # Find metadata by UID\n        all_metadata = metadata_manager.get_all_metadata()\n        content_meta = None\n        for meta in all_metadata:\n            if getattr(meta, \"uid\", None) == content_id:\n                content_meta = meta\n                break\n        \n        if not content_meta:\n            raise HTTPException(status_code=404, detail=\"Content not found\")\n        \n        proactive_surfacer.mark_surfaced(content_meta)\n        return {\"message\": \"Content marked as surfaced\"}\n    except HTTPException:\n        raise\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error marking content as surfaced: {str(e)}\")\n\n@cognitive_router.get(\"/proactive/stats\")\nasync def get_proactive_stats():\n    \"\"\"Get statistics about content surfacing\"\"\"\n    try:\n        stats = proactive_surfacer.get_surfacing_stats()\n        return stats\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting proactive stats: {str(e)}\")\n\n# Temporal Engine endpoints\n@cognitive_router.get(\"/temporal/relationships\", response_model=List[TemporalRelationship])\nasync def get_temporal_relationships(\n    max_delta_days: int = Query(7, ge=1, le=365)\n):\n    \"\"\"Get temporal relationships between content items\"\"\"\n    try:\n        insights = temporal_engine.find_temporal_relationships(max_delta_days=max_delta_days)\n        relationships = insights.get(\"relationships\", [])\n        \n        result = []\n        for rel in relationships:\n            result.append(TemporalRelationship(\n                from_title=getattr(rel.get(\"item1\"), \"title\", \"Untitled\"),\n                to_title=getattr(rel.get(\"item2\"), \"title\", \"Untitled\"),\n                days_apart=rel.get(\"time_delta_days\", 0),\n                relationship_type=rel.get(\"relationship_type\", \"unknown\"),\n                shared_tags=rel.get(\"shared_tags\", [])\n            ))\n        return result\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting temporal relationships: {str(e)}\")\n\n@cognitive_router.get(\"/temporal/insights\")\nasync def get_temporal_insights():\n    \"\"\"Get temporal insights about content patterns\"\"\"\n    try:\n        insights = temporal_engine.find_temporal_relationships()\n        return {\n            \"temporal_patterns\": insights.get(\"temporal_patterns\", {}),\n            \"seasonal_insights\": insights.get(\"seasonal_insights\", {}),\n            \"content_velocity\": insights.get(\"content_velocity\", {})\n        }\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting temporal insights: {str(e)}\")\n\n# Socratic Question Engine endpoints\n@cognitive_router.post(\"/socratic/questions\", response_model=List[SocraticQuestion])\nasync def generate_questions(\n    content: str,\n    difficulty_level: int = Query(1, ge=1, le=5)\n):\n    \"\"\"Generate Socratic questions from content\"\"\"\n    try:\n        if difficulty_level == 1:\n            questions = question_engine.generate_questions(content)\n        else:\n            # For higher difficulty levels, we would use the progressive question generator\n            questions = question_engine.generate_questions(content)\n        \n        result = []\n        for q in questions[:10]:  # Limit to 10 questions\n            result.append(SocraticQuestion(\n                question=q,\n                difficulty_level=difficulty_level\n            ))\n        return result\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error generating questions: {str(e)}\")\n\n@cognitive_router.get(\"/socratic/questions/{content_id}\", response_model=List[SocraticQuestion])\nasync def generate_questions_for_content(content_id: str):\n    \"\"\"Generate Socratic questions for a specific content item\"\"\"\n    try:\n        # Find metadata by UID\n        all_metadata = metadata_manager.get_all_metadata()\n        content_meta = None\n        for meta in all_metadata:\n            if getattr(meta, \"uid\", None) == content_id:\n                content_meta = meta\n                break\n        \n        if not content_meta:\n            raise HTTPException(status_code=404, detail=\"Content not found\")\n        \n        # Try to load content text\n        content_text = \"\"\n        content_path = getattr(content_meta, \"content_path\", None)\n        if content_path and os.path.exists(content_path):\n            with open(content_path, \"r\", encoding=\"utf-8\") as f:\n                content_text = f.read()[:1000]  # First 1000 characters\n        \n        if not content_text:\n            content_text = getattr(content_meta, \"title\", \"\") or \"Content\"\n        \n        questions = question_engine.generate_questions(content_text, content_meta)\n        \n        result = []\n        for q in questions[:10]:  # Limit to 10 questions\n            result.append(SocraticQuestion(question=q))\n        return result\n    except HTTPException:\n        raise\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error generating questions for content: {str(e)}\")\n\n# Recall Engine endpoints\n@cognitive_router.get(\"/recall/items\", response_model=List[RecallItem])\nasync def get_recall_items(\n    limit: int = Query(10, ge=1, le=100)\n):\n    \"\"\"Get items scheduled for review\"\"\"\n    try:\n        items = recall_engine.get_items_for_review(limit=limit)\n        result = []\n        for item in items:\n            meta = item.get(\"metadata\", {})\n            review_data = item.get(\"review_data\", {})\n            result.append(RecallItem(\n                title=getattr(meta, \"title\", \"Untitled\"),\n                last_reviewed=review_data.get(\"last_reviewed\"),\n                review_count=review_data.get(\"review_count\"),\n                difficulty_score=item.get(\"difficulty_score\"),\n                review_urgency=item.get(\"review_urgency\")\n            ))\n        return result\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting recall items: {str(e)}\")\n\n@cognitive_router.post(\"/recall/items/{content_id}/mark-reviewed\")\nasync def mark_item_reviewed(\n    content_id: str,\n    success: bool = True,\n    difficulty_rating: Optional[int] = None\n):\n    \"\"\"Mark a content item as reviewed\"\"\"\n    try:\n        # Find metadata by UID\n        all_metadata = metadata_manager.get_all_metadata()\n        content_meta = None\n        for meta in all_metadata:\n            if getattr(meta, \"uid\", None) == content_id:\n                content_meta = meta\n                break\n        \n        if not content_meta:\n            raise HTTPException(status_code=404, detail=\"Content not found\")\n        \n        recall_engine.mark_reviewed(content_meta, success, difficulty_rating)\n        return {\"message\": \"Item marked as reviewed\"}\n    except HTTPException:\n        raise\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error marking item as reviewed: {str(e)}\")\n\n@cognitive_router.get(\"/recall/analytics\")\nasync def get_recall_analytics():\n    \"\"\"Get analytics about recall performance\"\"\"\n    try:\n        analytics = recall_engine.get_review_analytics()\n        return analytics\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting recall analytics: {str(e)}\")\n\n# Pattern Detector endpoints\n@cognitive_router.get(\"/patterns/tags\", response_model=List[TagPattern])\nasync def get_tag_patterns(\n    min_frequency: int = Query(2, ge=1)\n):\n    \"\"\"Get tag usage patterns\"\"\"\n    try:\n        patterns = pattern_detector.detect_tag_patterns(min_frequency=min_frequency)\n        tag_frequencies = patterns.get(\"tag_frequencies\", {})\n        \n        result = []\n        for tag, freq in list(tag_frequencies.items())[:50]:  # Limit to 50 tags\n            result.append(TagPattern(\n                tag=tag,\n                frequency=freq\n            ))\n        return result\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting tag patterns: {str(e)}\")\n\n@cognitive_router.get(\"/patterns/insights\")\nasync def get_pattern_insights():\n    \"\"\"Get high-level insights about content patterns\"\"\"\n    try:\n        insights = pattern_detector.get_pattern_insights()\n        return insights\n    except Exception as e:\n        raise HTTPException(status_code=500, detail=f\"Error getting pattern insights: {str(e)}\")\n\n# Health check for cognitive features service\n@cognitive_router.get(\"/health\")\nasync def cognitive_health_check():\n    \"\"\"Health check for cognitive features service\"\"\"\n    try:\n        # Test each cognitive feature\n        proactive_stats = proactive_surfacer.get_surfacing_stats()\n        temporal_insights = temporal_engine.find_temporal_relationships()\n        pattern_insights = pattern_detector.get_pattern_insights()\n        \n        return {\n            \"status\": \"healthy\",\n            \"service\": \"Atlas Cognitive Features Service\",\n            \"features\": {\n                \"proactive_surfacer\": \"operational\",\n                \"temporal_engine\": \"operational\",\n                \"question_engine\": \"operational\",\n                \"recall_engine\": \"operational\",\n                \"pattern_detector\": \"operational\"\n            }\n        }\n    except Exception as e:\n        return {\n            \"status\": \"degraded\",\n            \"service\": \"Atlas Cognitive Features Service\",\n            \"error\": str(e)\n        }